1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Customer {
11	  yearsWithMHPCO: number;
12	}
13	
14	interface Scenario {
15	  customer: Customer;
16	  steps: QuoteStep[];
17	}
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	};
24	
25	const PROCESSING_FEE = 5;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	
28	const itemPremium = (item: Item): number => {
29	  const base = BASE_PREMIUM[item.type];
30	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
31	};
32	
33	const quotePremium = (step: QuoteStep): number => {
34	  const total = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
35	  return Math.ceil(total) + PROCESSING_FEE;
36	};
37	
38	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
39	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
40	  return { results };
41	};
