1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ---- Edge case: empty policy ----
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // ---- Base premiums for single main items (+ fee) ----
15	  it("single sword, newcomer → premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single amulet, newcomer → premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single staff, newcomer → premium 93 G (80 base + 8 first-insurance + 5 fee)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it.todo("single potion → premium 45 G (40 base + 5 fee)");
37	
38	  // ---- Components and building blocks ----
39	  it.todo("2 runes → 50 G base premium (→ 55 G with fee)");
40	  it.todo("3 runes → 60 G base premium, block applies (→ 65 G with fee)");
41	  it.todo("4 runes → 100 G base premium, no block (→ 105 G with fee)");
42	  it.todo("7 runes → 175 G base premium (→ 180 G with fee)");
43	
44	  // ---- "Alike" components ----
45	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
46	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
47	
48	  // ---- Item-specific modifiers in isolation ----
49	  it.todo("cursed sword (steel, ench 3), newcomer → premium 165 G");
50	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (+30%)");
51	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
52	
53	  // ---- Modifier scope on multi-item policies ----
54	  it.todo("cursed sword + plain amulet → base 160 G, curse adds 50 G (of sword base) → 210 G before fee");
55	
56	  // ---- Policy-wide modifiers ----
57	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
58	  it.todo("first insurance → 10% initial assessment surcharge");
59	  it.todo("follow-up contract (2nd quote) → 15% discount on the contract");
60	
61	  // ---- Rounding ----
62	  it.todo("premium calc yielding 197.5 G → final premium 198 G (rounded up)");
63	  it.todo("payout calc yielding 350.5 G → final payout 350 G (rounded down)");
64	
65	  // ---- Claim: standard reimbursement ----
66	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full − 100 deductible)");
67	  it.todo("rune (value 250 G), damage 200 G → payout 100 G (full − 100 deductible)");
68	
69	  // ---- Claim: special clauses ----
70	  it.todo("dragon-material sword, ench 8, damage 1000 G → payout 400 G (50% then deductible)");
71	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (both clauses, 50% wins)");
72	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (dragon only: full then deductible)");
73	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (high-ench only: 50% then deductible)");
74	
75	  // ---- Claim: deductible per damage event ----
