78	  // ---- Claim: multiple items of the same type ----
79	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
80	  it.todo("two sword damages, two swords insured → each is a separate damage with own deductible");
81	  it.todo("more damages of a type than insured (2 sword damages, 1 sword) → CLI exits non-zero, claim rejected");
82	
83	  // ---- Cap and insurance sum ----
84	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
85	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
86	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
