91	  it.todo("claim references item not in policy (amulet when only sword insured) → CLI exits non-zero, error to stderr");
92	  it.todo("claim with negative amount (-200) → CLI exits non-zero, error to stderr");
93	
94	  // ---- Integration examples ----
95	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
96	  it.todo("long-standing customer (3y) second contract, cursed sword (steel, ench 7) → premium 160 G");
97	});
